import type {
  CSSObject,
  DefineComponentStyleSlotModifiers,
  DefineComponentStyleSlotProps,
} from "@yamada-ui/react"
import { defineComponentSlotStyle } from "@yamada-ui/react"

type Slot =
  | "button"
  | "content"
  | "footer"
  | "gap"
  | "group"
  | "groupContent"
  | "groupLabel"
  | "handle"
  | "header"
  | "item"
  | "itemContent"
  | "itemElement"
  | "itemIndicator"
  | "itemLabel"
  | "itemLink"
  | "itemTrigger"
  | "mainPanel"
  | "menu"
  | "root"
  | "sidePanel"

const sidebarMenuStyle: CSSObject = {
  alignItems: "center",
  cursor: "pointer",
  display: "flex",
  fontSize: "{side-panel-item-font-size}",
  gap: "{side-panel-space}",
  h: "{side-panel-item-size}",
  lineHeight: "{side-panel-item-size}",
  minW: "{side-panel-item-size}",
  overflowX: "hidden",
  px: "{side-panel-space}",
  rounded: "{side-panel-item-rounded}",
  transitionDuration: "moderate",
  transitionProperty: "common",
  userSelect: "none",
  w: "full",
  _hover: { bg: "bg.subtle" },
  _disabled: { layerStyle: "disabled" },
}

const getSidebarTransitionStyle = (
  transitionProperty: CSSObject["transitionProperty"],
) => ({
  transitionDuration: "{side-panel-duration}",
  transitionProperty,
  transitionTimingFunction: "{side-panel-timing-function}",
})

export const sidebarStyle = defineComponentSlotStyle<
  Slot,
  DefineComponentStyleSlotProps<
    Slot,
    {
      mode: "icon" | "offcanvas"
      placement: "end" | "start"
      shape: "circle" | "rounded" | "square"
      withGroupGuideLine: "true"
      withGuideLine: "false" | "true"
    }
  >,
  DefineComponentStyleSlotModifiers<Slot>,
  DefineComponentStyleSlotModifiers<
    Slot,
    "outline" | "solid" | "subtle" | "surface"
  >
>({
  base: {
    button: {},
    content: {
      alignItems: "stretch",
      display: "flex",
      flex: "1",
      flexDirection: "column",
      gap: "{side-panel-gap}",
      overflowY: "auto",
      px: "{side-panel-space}",
    },
    footer: {
      "& [data-menu]": { h: "auto", minW: "auto", p: "{side-panel-space}" },
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      gap: "{side-panel-gap}",
      p: "{side-panel-space}",
    },
    gap: {
      w: "{side-panel-expanded-width}",
      _animated: getSidebarTransitionStyle("width"),
      _groupCollapsed: { w: "{side-panel-collapsed-width}" },
    },
    group: {
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      _notFirst: { pt: "calc({side-panel-gap} * 3)" },
    },
    groupContent: {
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      gap: "{side-panel-gap}",
    },
    groupLabel: {
      color: "fg.muted",
      fontSize: "{side-panel-group-font-size}",
      h: "{side-panel-item-size}",
      lineHeight: "{side-panel-item-size}",
      mb: "{side-panel-gap}",
      minW: "{side-panel-item-size}",
      px: "{side-panel-space}",
      truncated: true,
    },
    handle: {
      focusVisibleRing: "none",
      insetY: "0",
      position: "absolute",
      transitionDuration: "moderate",
      transitionProperty: "backgrounds",
      w: "{side-panel-handle-width}",
      zIndex: "yamcha",
      _after: {
        insetY: "0",
        position: "absolute",
        transitionDuration: "moderate",
        transitionProperty: "left, right, background, transform",
        w: "1px",
      },
      _hover: { _after: { bg: "colorScheme.muted" } },
      _focusVisible: { _after: { bg: "colorScheme.outline" } },
    },
    header: {
      "& [data-menu]": { h: "auto", minW: "auto", p: "{side-panel-space}" },
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      p: "{side-panel-space}",
    },
    item: {
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      position: "relative",
    },
    itemContent: {
      "& > :first-of-type": { mt: "{side-panel-gap}" },
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      gap: "{side-panel-gap}",
    },
    itemElement: {
      display: "inline-center",
      gap: "{side-panel-gap}",
      _icon: { fontSize: "{side-panel-item-icon-size}" },
    },
    itemIndicator: {
      color: "fg.subtle",
      fontSize: "{side-panel-item-icon-size}",
      transformOrigin: "center",
      _animated: {
        transitionDuration: "moderate",
        transitionProperty: "transform",
      },
      _expanded: { transform: "rotate(90deg)" },
    },
    itemLabel: { flex: "1", textAlign: "left", truncated: true },
    itemLink: { focusVisibleRing: "inside", ...sidebarMenuStyle },
    itemTrigger: { focusVisibleRing: "inside", ...sidebarMenuStyle },
    mainPanel: { flex: "1" },
    menu: sidebarMenuStyle,
    root: {
      "--height": "100dvh",
      "--side-panel-depth-space": "calc(({side-panel-space} * 2) - 1px)",
      "--side-panel-duration": "durations.moderate",
      "--side-panel-expanded-width": "sizes.xs",
      "--side-panel-gap": "calc({side-panel-space} / 2)",
      "--side-panel-group-font-size": "fontSizes.xs",
      "--side-panel-handle-width": "calc({side-panel-space} * 2)",
      "--side-panel-height": "{height}",
      "--side-panel-item-font-size": "fontSizes.sm",
      "--side-panel-item-icon-size": "fontSizes.md",
      "--side-panel-item-size": "sizes.8",
      "--side-panel-space": "spaces.2",
      "--side-panel-timing-function": "linear",
      display: "flex",
      minH: "{height}",
      w: "full",
    },
    sidePanel: {
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      h: "{side-panel-height}",
      position: "fixed",
      w: "{side-panel-expanded-width}",
      _animated: getSidebarTransitionStyle("left, right, width"),
    },
  },

  props: {
    /**
     * The mode of the sidebar
     *
     * @default 'offcanvas'
     */
    mode: {
      icon: {
        footer: {
          "& [data-menu]": {
            _groupAnimated: getSidebarTransitionStyle("padding"),
            _groupCollapsed: { p: "0" },
          },
        },
        group: {
          _groupAnimated: getSidebarTransitionStyle("padding"),
          _groupCollapsed: { pt: "0" },
        },
        groupContent: {
          _groupAnimated: getSidebarTransitionStyle("padding"),
          _groupCollapsed: { ps: "0" },
        },
        groupLabel: {
          opacity: "1",
          _groupAnimated: getSidebarTransitionStyle("margin, opacity"),
          _groupCollapsed: {
            mt: "calc(({side-panel-item-size} + {side-panel-gap}) * -1)",
            opacity: "0",
            pointerEvents: "none",
          },
        },
        header: {
          "& [data-menu]": {
            _groupAnimated: getSidebarTransitionStyle("padding"),
            _groupCollapsed: { p: "0" },
          },
        },
        itemContent: {
          _groupAnimated: getSidebarTransitionStyle("padding"),
          _groupCollapsed: { ps: "0" },
        },
        itemIndicator: {
          opacity: "1",
          _groupAnimated: getSidebarTransitionStyle("opacity"),
          _groupCollapsed: { opacity: "0" },
        },
        itemLabel: {
          opacity: "1",
          _groupAnimated: getSidebarTransitionStyle("opacity"),
          _groupCollapsed: { opacity: "0" },
        },
        root: { "--side-panel-collapsed-width": "sizes.7xs" },
        sidePanel: {
          _groupCollapsed: { w: "{side-panel-collapsed-width}" },
        },
      },
      offcanvas: {
        handle: {
          _groupCollapsed: { _hover: { bg: "colorScheme.ghost" } },
        },
        root: { "--side-panel-collapsed-width": "0" },
      },
    },
    /**
     * The placement of the sidebar
     *
     * @default 'start'
     */
    placement: {
      end: {
        gap: { order: "2" },
        handle: {
          cursor: "e-resize",
          left: "0",
          transform: "translateX(-50%)",
          _after: {
            left: "50%",
            transform: "translateX(-50%)",
          },
          _groupCollapsed: { cursor: "w-resize" },
        },
        mainPanel: { order: "1" },
        sidePanel: { right: "0" },
      },
      start: {
        gap: { order: "1" },
        handle: {
          cursor: "w-resize",
          right: "0",
          transform: "translateX(50%)",
          _after: {
            right: "50%",
            transform: "translateX(50%)",
          },
          _groupCollapsed: { cursor: "e-resize" },
        },
        mainPanel: { order: "2" },
        sidePanel: { left: "0" },
      },
    },
    /**
     * The shape of the component
     *
     * @default 'rounded'
     */
    shape: {
      circle: {
        itemLink: { ps: "calc({side-panel-space} * 2)" },
        itemTrigger: { ps: "calc({side-panel-space} * 2)" },
        root: { "--side-panel-item-rounded": "radii.full" },
      },
      rounded: {
        root: { "--side-panel-item-rounded": "radii.l2" },
      },
      square: {
        root: { "--side-panel-item-rounded": "0" },
      },
    },
    /**
     * If `true`, display group guide lines.
     *
     * @default false
     */
    withGroupGuideLine: {
      true: {
        groupContent: {
          position: "relative",
          ps: "calc({side-panel-depth-space} * 2)",
          _before: {
            bg: "border",
            display: "block",
            h: "full",
            left: "{side-panel-depth-space}",
            position: "absolute",
            transform: "translateX(-50%)",
            w: "px",
            zIndex: "yamcha",
          },
        },
      },
    },
    /**
     * If `true`, display guide lines.
     *
     * @default false
     */
    withGuideLine: {
      false: {
        itemContent: { ps: "{side-panel-depth-space}" },
      },
      true: {
        itemContent: {
          position: "relative",
          ps: "calc({side-panel-depth-space} * 2)",
          _before: {
            bg: "border",
            display: "block",
            h: "calc({sizes.full} - {side-panel-gap})",
            left: "{side-panel-depth-space}",
            position: "absolute",
            top: "{side-panel-gap}",
            transform: "translateX(-50%)",
            w: "px",
            zIndex: "yamcha",
          },
        },
      },
    },
  },

  variants: {
    outline: {
      itemLink: { _selected: { layerStyle: "outline" } },
      itemTrigger: { _selected: { layerStyle: "outline" } },
    },
    solid: {
      itemLink: { _selected: { layerStyle: "solid" } },
      itemTrigger: { _selected: { layerStyle: "solid" } },
    },
    subtle: {
      itemLink: { _selected: { layerStyle: "subtle" } },
      itemTrigger: { _selected: { layerStyle: "subtle" } },
    },
    surface: {
      itemLink: { _selected: { layerStyle: "surface" } },
      itemTrigger: { _selected: { layerStyle: "surface" } },
    },
  },

  compounds: [
    {
      css: {
        handle: {
          _groupCollapsed: {
            _after: { right: "0", transform: "translateX(0%)" },
          },
        },
        sidePanel: {
          _groupCollapsed: { left: "calc({side-panel-expanded-width} * -1)" },
        },
      },
      mode: "offcanvas",
      placement: "start",
    },
    {
      css: {
        handle: {
          _groupCollapsed: {
            _after: { left: "0", transform: "translateX(0%)" },
          },
        },
        sidePanel: {
          _groupCollapsed: { right: "calc({side-panel-expanded-width} * -1)" },
        },
      },
      mode: "offcanvas",
      placement: "end",
    },
    {
      css: {
        groupContent: {
          _before: { ...getSidebarTransitionStyle("opacity") },
          _groupCollapsed: { _before: { opacity: "0", pointerEvents: "none" } },
        },
      },
      mode: "icon",
      withGroupGuideLine: true,
    },
    {
      css: {
        itemContent: {
          _before: getSidebarTransitionStyle("opacity"),
          _groupCollapsed: { _before: { opacity: "0", pointerEvents: "none" } },
        },
      },
      mode: "icon",
      withGuideLine: true,
    },
  ],

  defaultProps: {
    variant: "subtle",
    mode: "offcanvas",
    placement: "start",
    shape: "rounded",
    withGroupGuideLine: false,
    withGuideLine: false,
  },
})

export type SidebarStyle = typeof sidebarStyle

"use client"

import type { FC, PropsWithChildren, ReactNode } from "react"
import type {
  Breakpoint,
  ExtractStyleValue,
  HTMLProps,
  HTMLStyledProps,
  ThemeProps,
  ReactNodeOrFunction,
} from "@yamada-ui/react"
import type { CollapseProps } from "../collapse"
import type { Loading } from "../loading"
import type { WithTransitionProps } from "../motion"
import type {
  UseSidebarGroupProps,
  UseSidebarGroupReturn,
  UseSidebarItemProps,
  UseSidebarItemReturn,
  UseSidebarProps,
  UseSidebarReturn,
} from "./use-sidebar"
import {
  Children,
  cloneElement,
  isValidElement,
  useCallback,
  useMemo,
} from "react"
import {
  createSlotComponent,
  mergeProps,
  styled,
  cast,
  createContext,
  dataAttr,
  isObject,
  isString,
  runIfFn,
  useIncludesChildren,
  useSplitChildren,
  useValidChildren,
} from "@yamada-ui/react"
import { useBreakpointValue } from "../../hooks/use-breakpoint"
import { useValue } from "../../hooks/use-value"
import { Collapse } from "../collapse"
import { Drawer } from "../drawer"
import { ChevronRightIcon } from "../icon"
import { useLoadingComponent } from "../loading"
import { Tooltip, type TooltipProps } from "../tooltip"
import { sidebarStyle, type SidebarStyle } from "./sidebar.style"
import {
  SidebarContext,
  SidebarDescendantsContext,
  SidebarItemContext,
  useSidebar,
  useSidebarContext,
  useSidebarGroup,
  useSidebarItem,
} from "./use-sidebar"

interface SidebarItemCallBackProps {
  disabled?: boolean
  expanded?: boolean
}

type SidebarItemReactNode =
  | ReactNodeOrFunction<SidebarItemCallBackProps>
  | {
      group: ReactNodeOrFunction<SidebarItemCallBackProps>
      item?: ReactNodeOrFunction<SidebarItemCallBackProps>
    }
  | {
      item: ReactNodeOrFunction<SidebarItemCallBackProps>
      group?: ReactNodeOrFunction<SidebarItemCallBackProps>
    }

interface SidebarItemSharedRenderProps
  extends
    Pick<SidebarItemProps, "label">,
    Pick<
      UseSidebarItemReturn,
      | "expanded"
      | "expandedValue"
      | "onExpandedChange"
      | "onSelectedChange"
      | "selected"
      | "selectedValue"
      | "value"
    > {
  itemProps: HTMLStyledProps<"li">
  linkProps: HTMLStyledProps<"a">
  triggerProps: HTMLStyledProps<"button">
  endElement?: ReactNode
  startElement?: ReactNode
}

interface SidebarItemRenderProps
  extends
    PropsWithChildren,
    Omit<SidebarItemSharedRenderProps, "endElement" | "startElement">,
    Pick<
      UseSidebarItemReturn,
      | "group"
      | "groupLoading"
      | "groupOpen"
      | "onGroupClose"
      | "onGroupOpen"
      | "onGroupToggle"
    > {
  endElement: { group?: ReactNode; item?: ReactNode }
  startElement: { group?: ReactNode; item?: ReactNode }
  indicator?: ReactNode
  link?: ReactNode
  trigger?: ReactNode
}

interface SidebarItemLinkRenderProps extends Omit<
  SidebarItemSharedRenderProps,
  "itemProps" | "triggerProps"
> {}

interface SidebarItemTriggerRenderProps
  extends
    Omit<SidebarItemSharedRenderProps, "itemProps" | "linkProps">,
    Pick<
      UseSidebarItemReturn,
      | "groupLoading"
      | "groupOpen"
      | "onGroupClose"
      | "onGroupOpen"
      | "onGroupToggle"
    > {
  indicator?: ReactNode
}

interface SidebarItemRender {
  item?: ReactNodeOrFunction<SidebarItemRenderProps>
  link?: ReactNodeOrFunction<SidebarItemLinkRenderProps>
  trigger?: ReactNodeOrFunction<SidebarItemTriggerRenderProps>
}

interface SidebarGroup extends Omit<SidebarGroupProps, "children" | "value"> {
  children: SidebarItemWithValue[]
  group: true
}

export interface SidebarItemWithValue extends Omit<
  SidebarItemProps,
  "children"
> {
  children?: SidebarItemWithValue[]
}

export type SidebarItem = SidebarGroup | SidebarItemWithValue

const createKey = (props: SidebarItem, index: number) => {
  return "value" in props ? props.value || index : index
}

const getReactNodeOrFunction = (
  type: "group" | "item",
  custom?: SidebarItemReactNode,
  root?: SidebarItemReactNode,
): ReactNodeOrFunction<SidebarItemCallBackProps> => {
  if (isObject(custom) && ("group" in custom || "item" in custom)) {
    return custom[type]
  } else if (custom) {
    return custom
  } else if (isObject(root) && ("group" in root || "item" in root)) {
    return root[type]
  } else {
    return root
  }
}

interface ComponentContext extends Pick<
  UseSidebarReturn,
  | "getContentProps"
  | "getFooterProps"
  | "getHeaderProps"
  | "getSidePanelProps"
  | "getTriggerProps"
> {
  breakpoint: ExtractStyleValue<NonNullable<SidebarRootProps["breakpoint"]>>
  mode: ExtractStyleValue<NonNullable<SidebarRootProps["mode"]>>
  placement: ExtractStyleValue<NonNullable<SidebarRootProps["placement"]>>
}

interface GroupComponentContext
  extends
    Pick<SidebarGroupProps, "contentProps" | "labelProps">,
    Pick<UseSidebarGroupReturn, "getContentProps" | "getLabelProps"> {}

const [GroupComponentContext, useGroupComponentContext] =
  createContext<GroupComponentContext>({ name: "GroupComponentContext" })

interface ItemComponentContext {
  contentProps: SidebarItemContentProps
  endElementProps: SidebarItemEndElementProps
  indicatorProps: SidebarItemIndicatorProps
  labelProps: SidebarItemLabelProps
  startElementProps: SidebarItemStartElementProps
  tooltipProps: SidebarItemTooltipProps
}

const [ItemComponentContext, useItemComponentContext] =
  createContext<ItemComponentContext>({ name: "ItemComponentContext" })

interface SidePanelComponentContext extends Pick<
  SidebarSidePanelProps,
  | "animated"
  | "contentProps"
  | "endElement"
  | "endElementProps"
  | "footerProps"
  | "groupContentProps"
  | "groupProps"
  | "handleProps"
  | "headerProps"
  | "indicator"
  | "indicatorHidden"
  | "indicatorProps"
  | "itemContentProps"
  | "itemProps"
  | "items"
  | "labelProps"
  | "linkProps"
  | "loadingScheme"
  | "menuProps"
  | "render"
  | "startElement"
  | "startElementProps"
  | "tooltipProps"
  | "triggerProps"
> {}

const [SidePanelComponentContext, useSidePanelComponentContext] =
  createContext<SidePanelComponentContext>({
    name: "SidePanelComponentContext",
  })

export interface SidebarRootProps
  extends
    HTMLStyledProps<"div">,
    ThemeProps<SidebarStyle>,
    Omit<UseSidebarProps, "mobile"> {
  /**
   * The breakpoint to use for the sidebar. If `false`, the sidebar will be always visible.
   *
   * @default 'md'
   */
  breakpoint?: Exclude<Breakpoint, "base"> | false
}

const {
  ComponentContext,
  PropsContext: SidebarPropsContext,
  useComponentContext,
  usePropsContext: useSidebarPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<SidebarRootProps, SidebarStyle, ComponentContext>(
  "sidebar",
  sidebarStyle,
)

export { SidebarPropsContext, useSidebarPropsContext }

/**
 * `Sidebar` is a component that is used to display a list of items in a sidebar.
 *
 * @see https://yamada-ui.com/docs/components/sidebar
 */
export const SidebarRoot = withProvider<
  "div",
  SidebarRootProps,
  "mode" | "placement"
>(
  ({
    breakpoint = "md",
    mode: modeProp = "offcanvas",
    placement: placementProp = "start",
    ...rest
  }) => {
    const mobile =
      useBreakpointValue<boolean | undefined>(
        breakpoint ? { [breakpoint]: true } : { base: false },
      ) ?? false
    const mode = useValue(modeProp)
    const placement = useValue(placementProp)
    const {
      descendants,
      expandedValue,
      open,
      selectedValue,
      getContentProps,
      getFooterProps,
      getHeaderProps,
      getRootProps,
      getSidePanelProps,
      getTriggerProps,
      onClose,
      onExpandedChange,
      onOpen,
      onSelectedChange,
      onToggle,
    } = useSidebar({ mobile, ...rest })
    const context = useMemo(
      () => ({
        expandedValue,
        mobile,
        open,
        selectedValue,
        onClose,
        onExpandedChange,
        onOpen,
        onSelectedChange,
        onToggle,
      }),
      [
        mobile,
        expandedValue,
        open,
        selectedValue,
        onClose,
        onExpandedChange,
        onOpen,
        onSelectedChange,
        onToggle,
      ],
    )
    const componentContext = useMemo(
      () => ({
        breakpoint,
        mode,
        placement,
        getContentProps,
        getFooterProps,
        getHeaderProps,
        getSidePanelProps,
        getTriggerProps,
      }),
      [
        breakpoint,
        mode,
        placement,
        getContentProps,
        getFooterProps,
        getHeaderProps,
        getSidePanelProps,
        getTriggerProps,
      ],
    )

    return (
      <SidebarDescendantsContext value={descendants}>
        <SidebarContext value={context}>
          <ComponentContext value={componentContext}>
            <styled.div data-group {...getRootProps()} />
          </ComponentContext>
        </SidebarContext>
      </SidebarDescendantsContext>
    )
  },
  "root",
  { transferProps: ["mode", "placement"] },
)()

export interface SidebarMainPanelProps extends HTMLStyledProps {}

export const SidebarMainPanel = withContext<"div", SidebarMainPanelProps>(
  "div",
  "mainPanel",
)()

export interface SidebarTriggerProps extends HTMLStyledProps<"button"> {}

export const SidebarTrigger = withContext<"button", SidebarTriggerProps>(
  "button",
  "trigger",
)(undefined, (props) => {
  const { getTriggerProps } = useComponentContext()

  return { asChild: true, ...getTriggerProps(props) }
})

export interface SidebarSidePanelProps
  extends
    Omit<HTMLStyledProps<"aside">, "content">,
    Pick<SidebarContentProps, "items">,
    Pick<
      SidebarItemProps,
      | "animated"
      | "endElement"
      | "endElementProps"
      | "indicator"
      | "indicatorProps"
      | "labelProps"
      | "linkProps"
      | "loadingScheme"
      | "render"
      | "startElement"
      | "startElementProps"
      | "tooltipProps"
      | "triggerProps"
    > {
  /**
   * The content of the sidebar.
   */
  content?: ReactNode
  /**
   * The footer of the sidebar.
   */
  footer?: ReactNode
  /**
   * The header of the sidebar.
   */
  header?: ReactNode
  /**
   * If `true`, hide the tree indicator icon for all items.
   *
   * @default false
   */
  indicatorHidden?: boolean
  /**
   * If `true`, the sidebar will be rendered with a handle.
   *
   * @default true
   */
  withHandle?: boolean
  /**
   * Props for the content component.
   */
  contentProps?: SidebarContentProps
  /**
   * Props for the drawer component.
   */
  drawerProps?: Omit<
    Drawer.RootProps,
    | "body"
    | "cancel"
    | "children"
    | "footer"
    | "header"
    | "middle"
    | "onCancel"
    | "onClose"
    | "onMiddle"
    | "onOpen"
    | "onSuccess"
    | "open"
    | "success"
    | "title"
    | "trigger"
  >
  /**
   * Props for the footer component.
   */
  footerProps?: SidebarFooterProps
  /**
   * Props for the group content component.
   */
  groupContentProps?: Omit<SidebarGroupContentProps, "children">
  /**
   * Props for the group component.
   */
